local StatusLabel = OptionsGroup:AddLabel("Estado: Inactivo", true)

OptionsGroup:AddToggle("AutoSpawn", {
	Text     = "Creación automática",
	Default  = false,
	Callback = function(v)
		if v and not state.selectedPetLabel then
			StatusLabel:SetText("Estado: No se ha seleccionado ninguna mascota.")
			Options.AutoSpawn:SetValue(false)
			return
		end
		state.autoSpawn = v
		StatusLabel:SetText(v and "Status: Creating..." or "Estado: Inactivo")
	end,
})

OptionsGroup:AddSlider("SpawnDelay", {
